$toName   = isset($_POST['to_name'])   ? $_POST['to_name']   : '';
$toAddr   = isset($_POST['to_addr'])   ? $_POST['to_addr']   : '';
$subject  = isset($_POST['subject'])   ? $_POST['subject']   : '';
$refNo    = isset($_POST['ref_no'])    ? $_POST['ref_no']    : '';
$date     = isset($_POST['date'])      ? $_POST['date']      : date('d.m.y');
$showLetter = $mailBody !== '';

$letterheadB64 = '';
$sigB64        = '';
?>
