  /* ── COMPOSER ── */
  .composer { max-width: 780px; margin: 48px auto; padding: 0 24px; display: <?= $showLetter ? 'none' : 'block' ?>; }
  .composer h1 { font-family: 'EB Garamond', serif; font-size: 2.1rem; font-weight: 500; color: var(--dark); }
