  .btn-sec:hover { background: var(--bg); }

  /* ── LETTER WRAP ── */
  .letter-wrap { display: <?= $showLetter ? 'block' : 'none' ?>; padding: 40px 24px 60px; }
  .actions { max-width: 794px; margin: 0 auto 18px; display: flex; gap: 12px; }

  /* ── A4 PAPER ── */
  .letter {
    width: 794px; min-height: 1123px; margin: 0 auto;
    background: var(--paper); position: relative; overflow: hidden;
    box-shadow: 0 4px 40px rgba(0,0,0,.12);
