    width: 100%; height: 225px;
    object-fit: cover; object-position: top center; display: block;
  }

  /* ── BODY ── */
  .letter-body { padding: 20px 62px 130px; position: relative; z-index: 1; }

  .letter-date { font-size: 1rem; color: var(--dark); margin-bottom: 22px; text-align: right; }

  .recipient { font-size: 1rem; line-height: 1.75; color: var(--dark); margin-bottom: 26px; }
