  .sig-block .sig-name { font-size: .85rem; color: var(--mid); margin-top: 4px; line-height: 1.6; }
  .sig-block .sig-name strong { color: var(--dark); font-size: .9rem; display: block; }
  .sig-block .sig-name em { font-style: normal; color: var(--orange); font-size: .8rem; }

  /* ── FOOTER ── */
  .letter-footer {
    position: absolute; bottom: 0; left: 0; right: 0;
    padding: 14px 50px; background: var(--dark);
    display: flex; justify-content: space-between; align-items: center;
    font-size: .68rem; color: rgba(255,255,255,.45); z-index: 2;
    font-family: 'DM Sans', sans-serif;
  }
  .letter-footer strong { color: rgba(255,255,255,.75); }

  /* ── PRINT ── */
  @media print {
    body { background: white; }
    .composer, .actions { display: none !important; }
    .letter-wrap { display: block !important; padding: 0; }
    .letter { box-shadow: none; width: 100%; min-height: unset; }
    .letter-footer { position: fixed; bottom: 0; }
    @page { margin: 0; size: A4; }
