<!-- ══ COMPOSER ══ -->
<div class="composer">
  <h1>Atire <span>(Pvt) Ltd</span></h1>
  <p class="sub">Official Letter Generator</p>
  <form method="POST" action="">
    <div class="form-grid">
      <div>
        <label>Date</label>
        <input type="text" name="date" placeholder="e.g. 10.04.26" value="<?= htmlspecialchars($date) ?>">
