<!-- ══ GENERATED LETTER ══ -->
<div class="letter-wrap">
  <div class="actions">
    <button class="btn btn-sec" onclick="window.print()">🖨 Print / Save PDF</button>
    <button class="btn btn-sec" onclick="document.querySelector('.letter-wrap').style.display='none';document.querySelector('.composer').style.display='block';">← Edit Letter</button>
  </div>

  <div class="letter">
    <!-- Scanned letterhead header -->
    <div class="lh-img">
      <img src="data:image/png;base64,<?= $letterheadB64 ?>" alt="Atire Letterhead">
    </div>

    <div class="letter-body">

      <!-- Date (right-aligned, matches PDF style) -->
      <div class="letter-date"><?= htmlspecialchars($date) ?></div>

      <!-- Recipient -->
      <?php if ($toName || $toAddr): ?>
      <div class="recipient">
        <?php if ($toName): ?><strong><?= nl2br(htmlspecialchars($toName)) ?></strong><br><?php endif; ?>
        <?php if ($toAddr): ?><?= nl2br(htmlspecialchars($toAddr)) ?><?php endif; ?>
      </div>
      <?php endif; ?>

      <!-- Ref line -->
      <?php if ($refNo): ?>
      <div class="ref-line"><strong>Invoice NO : <?= htmlspecialchars($refNo) ?></strong></div>
      <?php endif; ?>

      <!-- Subject -->
      <?php if ($subject): ?>
      <div class="subject-line"><?= htmlspecialchars($subject) ?></div>
      <?php endif; ?>

      <!-- Body — render bullet lines as <ul> -->
      <?php
        $lines = explode("\n", $mailBody);
        $output = '';
        $inList = false;
        foreach ($lines as $line) {
          $trimmed = rtrim($line);
          if (preg_match('/^[•\-]\s*(.+)/', $trimmed, $m)) {
            if (!$inList) { $output .= '<ul>'; $inList = true; }
            $output .= '<li>' . htmlspecialchars($m[1]) . '</li>';
          } else {
            if ($inList) { $output .= '</ul>'; $inList = false; }
            $output .= htmlspecialchars($trimmed) . "\n";
          }
        }
        if ($inList) $output .= '</ul>';
      ?>
      <div class="mail-content"><?= $output ?></div>

      <!-- Signature -->
      <div class="sig-block">
        <div class="company-name">ATIRE (PVT) LTD</div>
        <img src="data:image/png;base64,<?= $sigB64 ?>" alt="Signature">
        <div class="sig-name">
          <strong>G.D.A.P. Dharmasiri</strong>
          <em>General Manager — Administration</em>
        </div>
      </div>

    </div><!-- /letter-body -->

    <div class="letter-footer">
      <span><strong>Atire (Pvt) Ltd.</strong> — Reg. PV20795</span>
      <span>No. 02, Udugalla Estate, Paragasthota, Bandaragama, Sri Lanka</span>
      <span>support@atire.com · www.atire.com</span>
    </div>
  </div><!-- /letter -->
</div><!-- /letter-wrap -->

